const raw = $input.first().json ?? {};
const body = raw.body ?? raw;
const normalize = (value) => String(value ?? '').trim();
const generatedAt = new Date().toISOString();

const shortToken = normalize(body.short_token || body.token);
const accountId = normalize(body.account_id || '17841440667412938');
const appSecret = normalize(body.app_secret || '749e29f8214e8da77b9afc1a284c2276');
const action = normalize(body.action || 'exchange').toLowerCase();

const buildError = (message, extra = {}) => [{
  json: {
    status: 'error',
    action,
    message,
    generated_at: generatedAt,
    ...extra,
  },
}];

if (!shortToken) {
  return buildError('Se requiere short_token o token en el body.');
}

if (!appSecret) {
  return buildError('Se requiere app_secret.');
}

const request = this.helpers.request;
const requestDefaults = {
  json: true,
  simple: false,
  resolveWithFullResponse: true,
  headers: {
    Accept: 'application/json',
    'User-Agent': 'n8n-token-manager-ig/1.0',
  },
};

// Step 1: Validate current token
if (action === 'validate') {
  try {
    const validateResp = await request({
      ...requestDefaults,
      method: 'GET',
      uri: `https://graph.instagram.com/v21.0/me`,
      qs: { fields: 'id,username', access_token: shortToken },
    });
    const vBody = validateResp?.body ?? {};
    const valid = validateResp?.statusCode === 200 && !!vBody.id;
    return [{ json: {
      status: valid ? 'success' : 'error',
      action: 'validate',
      valid,
      account_id: vBody.id || null,
      username: vBody.username || null,
      generated_at: generatedAt,
    }}];
  } catch (e) {
    return buildError('Error validando token: ' + e.message);
  }
}

// Step 2: Exchange short-lived for long-lived (60 days)
const exchangeResp = await request({
  ...requestDefaults,
  method: 'GET',
  uri: 'https://graph.instagram.com/access_token',
  qs: {
    grant_type: 'ig_exchange_token',
    client_secret: appSecret,
    access_token: shortToken,
  },
});

const exchangeBody = exchangeResp?.body ?? {};
if (Number(exchangeResp?.statusCode || 500) >= 400 || !exchangeBody.access_token) {
  // Try refresh instead (for tokens that are already long-lived)
  const refreshResp = await request({
    ...requestDefaults,
    method: 'GET',
    uri: 'https://graph.instagram.com/refresh_access_token',
    qs: {
      grant_type: 'ig_refresh_token',
      access_token: shortToken,
    },
  });
  const refreshBody = refreshResp?.body ?? {};
  if (Number(refreshResp?.statusCode || 500) >= 400 || !refreshBody.access_token) {
    return buildError('No se pudo intercambiar ni refrescar el token.', {
      exchange_error: exchangeBody?.error ?? exchangeBody,
      refresh_error: refreshBody?.error ?? refreshBody,
    });
  }
  // Refresh succeeded
  const newToken = normalize(refreshBody.access_token);
  const expiresIn = Number(refreshBody.expires_in || 0);
  return [{ json: {
    status: 'success',
    action: 'refresh',
    access_token: newToken,
    token_type: refreshBody.token_type || 'bearer',
    expires_in_seconds: expiresIn,
    expires_in_days: expiresIn > 0 ? Math.round(expiresIn / 86400) : null,
    expires_at: expiresIn > 0 ? new Date(Date.now() + expiresIn * 1000).toISOString() : null,
    account_id: accountId,
    generated_at: generatedAt,
    method: 'ig_refresh_token',
  }}];
}

// Exchange succeeded
const longToken = normalize(exchangeBody.access_token);
const expiresIn = Number(exchangeBody.expires_in || 0);

return [{ json: {
  status: 'success',
  action: 'exchange',
  access_token: longToken,
  token_type: exchangeBody.token_type || 'bearer',
  expires_in_seconds: expiresIn,
  expires_in_days: expiresIn > 0 ? Math.round(expiresIn / 86400) : null,
  expires_at: expiresIn > 0 ? new Date(Date.now() + expiresIn * 1000).toISOString() : null,
  account_id: accountId,
  generated_at: generatedAt,
  method: 'ig_exchange_token',
}}];
